import React, { Component, useEffect } from "react";
import "./App.css";
class Slider extends Component {
  constructor(props) {
    super(props);
    this.state = {
      timer: null,
      number: 0,
    };
    componentDidMount = () => {
      setTimeout(() => {
        if (this.state.number === 0) {
          this.setState((this.state.number = 1));
          console.log(this.state.number);
        } else {
          this.setState((this.state.number = 0));
          console.log(this.state.number);
        }
      }, 1000);
    };
  }
  render() {
    const photoes = [
      "https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80",

      "https://images.unsplash.com/photo-1633356122544-f134324a6cee?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1470&q=80",
    ];
    return (
      <div className="divSlider">
        <img
          className="photo1"
          src={photoes[this.state.number]}
          alt="programmingPhoto1"
        />
      </div>
    );
  }
}
